1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	const FIRST_INSURANCE_MULTIPLIER = 1.1;
21	
22	// Round up in MHPCO's favour, guarding against floating-point noise
23	// (e.g. 197.50000000001 should still round to 198, not 199).
24	const roundUpInMHPCOFavor = (amount: number): number =>
25	  Math.ceil(Number(amount.toFixed(6)));
26	
27	export const quote = (
28	  items: Item[],
29	  customer: Customer,
30	  contractIndex: number,
31	): number => {
32	  const policyBase = items.reduce(
33	    (sum, item) => sum + BASE_PREMIUMS[item.type] * FIRST_INSURANCE_MULTIPLIER,
34	    0,
35	  );
36	  const total = policyBase + PROCESSING_FEE;
37	  return roundUpInMHPCOFavor(total);
38	};
39	
40	export const claim = (): number => {
41	  return undefined as unknown as number;
42	};
